import java.util.Arrays;
import java.util.Comparator;

public class UnionFind {
    private int[] parent;
    private int[] rank;

    public UnionFind(int size) {
        parent = new int[size];
        rank = new int[size];
        for (int i = 0; i < size; i++) {
            parent[i] = i;
        }
    }

    public int find(int u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    public boolean union(int u, int v) {
        int rootU = find(u);
        int rootV = find(v);
        if (rootU == rootV) return false;

        if (rank[rootU] > rank[rootV]) {
            parent[rootV] = rootU;
        } else if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
        } else {
            parent[rootV] = rootU;
            rank[rootU]++;
        }
        return true;
    }
}

public static long solve(long n, long[][] edges, long k) {
    Arrays.sort(edges, Comparator.comparingLong(a -> a[2]));
    UnionFind uf = new UnionFind((int) n);
    long components = n;
    long maxCost = 0;

    for (long[] edge : edges) {
        if (components <= k) break;
        int u = (int) edge[0];
        int v = (int) edge[1];
        long w = edge[2];
        if (uf.find(u) != uf.find(v)) {
            uf.union(u, v);
            components--;
            maxCost = Math.max(maxCost, w);
        }
    }

    return maxCost;
}
